diff --git a/src/test/java/com/finbit/finscore/FinscoreBoundaryTest.java b/src/test/java/com/finbit/finscore/FinscoreBoundaryTest.java
new file mode 100644
index 0000000..fb65496
--- /dev/null
+++ b/src/test/java/com/finbit/finscore/FinscoreBoundaryTest.java
@@ -0,0 +1,364 @@
+package com.finbit.finscore;
+
+import com.finbit.finscore.dto.PFM.BankScoreMonthlyTotalDTO;
+import com.finbit.finscore.dto.PFM.ChildCategoryDTO;
+import com.finbit.finscore.dto.PFM.ExpenseDetailDTO;
+import com.finbit.finscore.dto.PFM.MerchantAnalysisDTO;
+import com.finbit.finscore.dto.PFM.MerchantDetailDTO;
+import com.finbit.finscore.dto.PFM.MonthlyExpensesDTO;
+import com.finbit.finscore.dto.PFM.SpendingCategoryAnalysisDTO;
+import com.finbit.finscore.dto.bankScore.BankAnalysisDetailDTO;
+import com.finbit.finscore.dto.bankScore.BankScoreDataDTO;
+import com.finbit.finscore.dto.bankScore.BankScoreDetailDTO;
+import com.finbit.finscore.dto.bankScore.CustomerDetailDTO;
+import com.finbit.finscore.dto.bankScore.TransactionDateDetailDTO;
+import com.finbit.finscore.dto.response.finscore.FinScoreAnalysisResponseDTO;
+import com.finbit.finscore.dto.scoreAnalysis.CategoryPercentDTO;
+import com.finbit.finscore.dto.scoreAnalysis.ScoreAnalysisDTO;
+import com.finbit.finscore.mapper.FinScoreAnalysisMapper;
+import org.junit.jupiter.api.Test;
+
+import java.util.ArrayList;
+import java.util.Arrays;
+import java.util.List;
+
+import static org.junit.jupiter.api.Assertions.assertEquals;
+import static org.junit.jupiter.api.Assertions.assertNotNull;
+import static org.junit.jupiter.api.Assertions.assertTrue;
+
+/**
+ * Boundary / edge-case correctness for the deterministic FinScore analysis math
+ * in {@link FinScoreAnalysisMapper}. Every assertion drives the public
+ * {@code getAnalysisReport(...)} entry point and inspects a single sub-result;
+ * the arithmetic lives several call hops deep in the private resolvers.
+ *
+ * The wider application only ever exercises this mapper through live upstream
+ * responses that sit comfortably inside the ranges, so the boundary slips
+ * asserted here (a max/min extremum, the leading sorted element, an average
+ * vs. total divisor, a top-N cap, and a percent scale factor) stay invisible
+ * to the context-load smoke test that ships with the repo.
+ */
+public class FinscoreBoundaryTest {
+
+    private static final double EPS = 1e-6;
+
+    // ---- builders -----------------------------------------------------------
+
+    @SafeVarargs
+    private static <T> List<T> list(T... items) {
+        return new ArrayList<>(Arrays.asList(items));
+    }
+
+    private static MonthlyExpensesDTO me(String monthYear, double value) {
+        MonthlyExpensesDTO m = new MonthlyExpensesDTO();
+        m.setMonthYear(monthYear);
+        m.setValue(value);
+        return m;
+    }
+
+    private static MonthlyExpensesDTO me(double value) {
+        return me("2022-01", value);
+    }
+
+    private static BankScoreMonthlyTotalDTO bankMonthly(double amount) {
+        BankScoreMonthlyTotalDTO b = new BankScoreMonthlyTotalDTO();
+        b.setMonthYear("2022-01");
+        b.setAmout(amount);
+        return b;
+    }
+
+    private static BankAnalysisDetailDTO analysis(String parameter, double average, double total, boolean withMonthly) {
+        BankAnalysisDetailDTO a = new BankAnalysisDetailDTO();
+        a.setParameter(parameter);
+        a.setAverage(average);
+        a.setTotal(total);
+        if (withMonthly) {
+            a.setMonthlyTotal(list(bankMonthly(total)));
+        }
+        return a;
+    }
+
+    private static SpendingCategoryAnalysisDTO cat(String parent, double total) {
+        SpendingCategoryAnalysisDTO c = new SpendingCategoryAnalysisDTO();
+        c.setParentCategory(parent);
+        c.setTotal(total);
+        return c;
+    }
+
+    private static SpendingCategoryAnalysisDTO cat(String parent, double total, double average) {
+        SpendingCategoryAnalysisDTO c = cat(parent, total);
+        c.setAverage(average);
+        return c;
+    }
+
+    private static ChildCategoryDTO child(String name, double total) {
+        ChildCategoryDTO c = new ChildCategoryDTO();
+        c.setChildCategory(name);
+        c.setTotal(total);
+        return c;
+    }
+
+    private static MerchantAnalysisDTO merchant(String name, double total) {
+        MerchantAnalysisDTO m = new MerchantAnalysisDTO();
+        m.setMerchant(name);
+        m.setTotal(total);
+        return m;
+    }
+
+    private static BankScoreDetailDTO bank(List<BankAnalysisDetailDTO> analysisDetails) {
+        BankScoreDataDTO data = new BankScoreDataDTO();
+        data.setBankAnalysisDetails(analysisDetails);
+        BankScoreDetailDTO b = new BankScoreDetailDTO();
+        b.setData(data);
+        return b;
+    }
+
+    private static ExpenseDetailDTO expense() {
+        return new ExpenseDetailDTO();
+    }
+
+    private static MerchantDetailDTO merchants(List<MerchantAnalysisDTO> ms) {
+        MerchantDetailDTO d = new MerchantDetailDTO();
+        d.setMerchantAnalysis(ms);
+        return d;
+    }
+
+    private static CategoryPercentDTO byCategory(List<CategoryPercentDTO> list, String category) {
+        for (CategoryPercentDTO c : list) {
+            if (category.equals(c.getCategory())) {
+                return c;
+            }
+        }
+        throw new AssertionError("category not found: " + category);
+    }
+
+    // ---- fail_to_pass : one per planted boundary defect ---------------------
+
+    /** D1: highest credit-card utilisation must be the MAX monthly value, not the min. */
+    @Test
+    public void creditCardUtilization_usesMaximumMonthlyValue() {
+        ExpenseDetailDTO exp = expense();
+        SpendingCategoryAnalysisDTO cc = cat("CREDIT_CARD_PAYMENT", 9000);
+        cc.setMonthlyTotal(list(me(1000), me(5000), me(3000)));
+        exp.setSpendingCategoryAnalysis(list(cc));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(new ArrayList<>()));
+
+        assertNotNull(r.getCreditCardUtilization());
+        assertEquals(5000.0, r.getCreditCardUtilization().getHighestCreditCardUtilization(), EPS);
+    }
+
+    /** D2: spending "percent of total income" reads the leading (largest) category. */
+    @Test
+    public void spendingCategories_percentOfIncomeUsesLeadingCategory() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("RENT", 3000), cat("FOOD", 1000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(list(analysis("Income", 8000, 10000, true))));
+
+        assertNotNull(r.getSpendingCategories());
+        assertEquals(30.0, r.getSpendingCategories().getPercentOfTotalIncome(), EPS);
+    }
+
+    /** D3: obligation share divides by AVERAGE monthly income, not total income. */
+    @Test
+    public void monthlyObligations_percentDividesByAverageIncome() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("LOAN_REPAYMENT", 2000, 2000), cat("MISC", 500)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(list(analysis("Income", 8000, 10000, true))));
+
+        assertNotNull(r.getMonthlyObligations());
+        assertEquals(25.0, r.getMonthlyObligations().getPercentageAverageMonthlyIncome(), EPS);
+    }
+
+    /** D4: with five or more merchants the report keeps the top five, not four. */
+    @Test
+    public void merchantSpending_keepsTopFiveMerchants() {
+        MerchantDetailDTO md = merchants(list(
+                merchant("A", 5000), merchant("B", 4000), merchant("C", 3000),
+                merchant("D", 2000), merchant("E", 1000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), md, bank(new ArrayList<>()));
+
+        assertNotNull(r.getMerchantSpending());
+        assertEquals(5, r.getMerchantSpending().getMerchantsSpendingList().size());
+    }
+
+    /** D5: average-monthly-income percent is scaled by 100 into a real percentage. */
+    @Test
+    public void incomeExpenses_averageMonthlyIncomePercentScaledTo100() {
+        BankScoreDetailDTO b = bank(list(
+                analysis("AverageBankBalance", 5000, 0, false),
+                analysis("Income", 8000, 10000, true)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), new MerchantDetailDTO(), b);
+
+        assertNotNull(r.getIncomeExpenses());
+        assertEquals(62.5, r.getIncomeExpenses().getAverageMonthlyIncomePercent(), EPS);
+    }
+
+    // ---- pass_to_pass : behaviour unchanged by the planted defects ----------
+
+    @Test
+    public void bankScore_customerFieldsAreMapped() {
+        CustomerDetailDTO cd = new CustomerDetailDTO();
+        cd.setAccountName("Jane Doe");
+        cd.setMobile("9990001111");
+        cd.setEmail("jane@example.com");
+        cd.setBankName("Acme Bank");
+        cd.setAccountNumber("00012345");
+        TransactionDateDetailDTO tdd = new TransactionDateDetailDTO();
+        tdd.setFromDate("2022-01-01");
+        tdd.setToDate("2022-06-30");
+        cd.setTransactionDateDetails(tdd);
+
+        BankScoreDataDTO data = new BankScoreDataDTO();
+        data.setCustomerDetails(cd);
+        BankScoreDetailDTO b = new BankScoreDetailDTO();
+        b.setData(data);
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), new MerchantDetailDTO(), b);
+
+        assertNotNull(r.getBankScore());
+        assertEquals("Jane Doe", r.getBankScore().getName());
+        assertEquals("jane@example.com", r.getBankScore().getEmail());
+        assertEquals("Acme Bank", r.getBankScore().getBankName());
+        assertEquals("2022-01-01", r.getBankScore().getStartDate());
+        assertEquals("2022-06-30", r.getBankScore().getEndDate());
+    }
+
+    @Test
+    public void monthlyIncomeAnalysis_incomeReadFromBankAnalysis() {
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), new MerchantDetailDTO(), bank(list(analysis("Income", 8000, 96000, false))));
+
+        assertNotNull(r.getMonthlyIncomeAnalysis());
+        assertEquals(8000.0, r.getMonthlyIncomeAnalysis().getAverageMonthlyIncome(), EPS);
+        assertEquals(96000.0, r.getMonthlyIncomeAnalysis().getIncome(), EPS);
+    }
+
+    @Test
+    public void monthlyIncomeAnalysis_expensesAreSummedAndRounded() {
+        ExpenseDetailDTO exp = expense();
+        exp.setMonthwiseSpendingAnalysis(list(me("2022-01", 100.0), me("2022-02", 200.0), me("2022-03", 50.0)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(new ArrayList<>()));
+
+        assertEquals(350.0, r.getMonthlyIncomeAnalysis().getExpenses(), EPS);
+    }
+
+    @Test
+    public void monthlyIncomeAnalysis_investmentsAndObligationsFromCategories() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("INVESTMENT", 1500), cat("LOAN_REPAYMENT", 800)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(new ArrayList<>()));
+
+        assertEquals(1500.0, r.getMonthlyIncomeAnalysis().getInvestments(), EPS);
+        assertEquals(800.0, r.getMonthlyIncomeAnalysis().getObligations(), EPS);
+    }
+
+    @Test
+    public void spendingCategories_perCategoryPercentAndOrdering() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("A", 6000), cat("B", 2000), cat("C", 2000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(new ArrayList<>()));
+
+        List<CategoryPercentDTO> cats = r.getSpendingCategories().getSpendingCategoryList();
+        assertEquals(3, cats.size());
+        assertEquals("A", cats.get(0).getCategory());
+        assertTrue(cats.get(0).getTotal() >= cats.get(1).getTotal());
+        assertEquals(60.0, byCategory(cats, "A").getPercent(), EPS);
+        assertEquals(20.0, byCategory(cats, "B").getPercent(), EPS);
+    }
+
+    @Test
+    public void spendingCategories_roundOffKeepsTwoDecimals() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("X", 1000), cat("Y", 2000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(new ArrayList<>()));
+
+        List<CategoryPercentDTO> cats = r.getSpendingCategories().getSpendingCategoryList();
+        assertEquals(33.33, byCategory(cats, "X").getPercent(), EPS);
+        assertEquals(66.67, byCategory(cats, "Y").getPercent(), EPS);
+    }
+
+    @Test
+    public void investments_percentOfIncomeUsesLeadingChild() {
+        ExpenseDetailDTO exp = expense();
+        SpendingCategoryAnalysisDTO inv = cat("INVESTMENT", 4000);
+        inv.setChildCategories(list(child("MUTUAL_FUND", 3000), child("STOCK", 1000)));
+        exp.setSpendingCategoryAnalysis(list(inv, cat("MISC", 1000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(list(analysis("Income", 8000, 8000, true))));
+
+        assertEquals(37.5, r.getInvestments().getPercentOfTotalIncome(), EPS);
+    }
+
+    @Test
+    public void monthlyObligations_stableWhenAverageEqualsTotalIncome() {
+        ExpenseDetailDTO exp = expense();
+        exp.setSpendingCategoryAnalysis(list(cat("LOAN_REPAYMENT", 1000, 1000), cat("MISC", 500)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                exp, new MerchantDetailDTO(), bank(list(analysis("Income", 5000, 5000, true))));
+
+        assertEquals(20.0, r.getMonthlyObligations().getPercentageAverageMonthlyIncome(), EPS);
+    }
+
+    @Test
+    public void merchantSpending_belowFiveKeepsAllMerchants() {
+        MerchantDetailDTO md = merchants(list(
+                merchant("A", 3000), merchant("B", 2000), merchant("C", 1000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), md, bank(new ArrayList<>()));
+
+        assertEquals(3, r.getMerchantSpending().getMerchantsSpendingList().size());
+        assertEquals("A", r.getMerchantSpending().getMerchantsSpendingList().get(0).getCategory());
+    }
+
+    @Test
+    public void merchantSpending_percentageTotalIncomeUsesLeadingMerchant() {
+        MerchantDetailDTO md = merchants(list(merchant("A", 4000), merchant("B", 1000)));
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(
+                expense(), md, bank(list(analysis("Income", 8000, 8000, true))));
+
+        assertEquals(50.0, r.getMerchantSpending().getPercentageTotalIncome(), EPS);
+    }
+
+    @Test
+    public void scoreAnalysis_isPassedThrough() {
+        ScoreAnalysisDTO s1 = new ScoreAnalysisDTO();
+        s1.setParameter("Investments");
+        s1.setStatus("GOOD");
+        ScoreAnalysisDTO s2 = new ScoreAnalysisDTO();
+        s2.setParameter("ExpenseToIncome");
+        s2.setStatus("AVERAGE");
+
+        BankScoreDataDTO data = new BankScoreDataDTO();
+        data.setScoreAnalysis(list(s1, s2));
+        BankScoreDetailDTO b = new BankScoreDetailDTO();
+        b.setData(data);
+
+        FinScoreAnalysisResponseDTO r = FinScoreAnalysisMapper.getAnalysisReport(expense(), new MerchantDetailDTO(), b);
+
+        assertEquals(2, r.getScoreAnalysis().size());
+        assertEquals("Investments", r.getScoreAnalysis().get(0).getParameter());
+    }
+}
